function addAuditLog(user, action, type) {
  const newLog = {
    id: auditLogs.length + 1,
    timestamp: (/* @__PURE__ */ new Date()).toISOString(),
    user,
    action,
    type
  };
  auditLogs.unshift(newLog);
}
function loadLocalLaws() {
  const result = [];
  try {
    const dirPath = import_path.default.join(process.cwd(), "laws");
    if (import_fs.default.existsSync(dirPath)) {
      const files = import_fs.default.readdirSync(dirPath);
      for (const file of files) {
        if (file.endsWith(".txt") || file.endsWith(".md")) {
          const filePath = import_path.default.join(dirPath, file);
          const content = import_fs.default.readFileSync(filePath, "utf-8");
          result.push({
            name: file.replace(".txt", "").replace(".md", ""),
            content
          });
        }
      }
    }
  } catch (error) {
    console.error("\u0413\u0440\u0435\u0448\u043A\u0430 \u043F\u0440\u0438 \u0447\u0438\u0442\u0430\u045A\u0435 \u043D\u0430 \u043B\u043E\u043A\u0430\u043B\u043D\u0438\u0442\u0435 \u0437\u0430\u043A\u043E\u043D\u0438: ", error);
  }
  return result;
}
